canon as (
  select distinct
    trim(parent_category) as parent_category,
    trim(product) as product,
    nullif(trim(sub_category), '') as sub_category,
    lower(regexp_replace(trim(parent_category), '[^a-zA-Z0-9]+', '-', 'g')) as parent_slug,
    lower(regexp_replace(trim(product), '[^a-zA-Z0-9]+', '-', 'g')) as product_slug,
    case when nullif(trim(sub_category), '') is null then null else lower(regexp_replace(trim(sub_category), '[^a-zA-Z0-9]+', '-', 'g')) end as sub_slug
  from seed_rows
),
product_targets as (
  select
    c.parent_category,
    c.product,
    c.sub_category,
    coalesce(c.sub_category, c.product) as product_name,
    coalesce(c.sub_slug, c.product_slug) as leaf_slug,
    case when c.sub_category is null then
      lower(regexp_replace(c.parent_category || '-' || c.product, '[^a-zA-Z0-9]+', '-', 'g'))
    else
      lower(regexp_replace(c.parent_category || '-' || c.product || '-' || c.sub_category, '[^a-zA-Z0-9]+', '-', 'g'))
    end as product_slug,
    cat.id as category_id
  from canon c
  cross join tenant t
  join val_dev.catalog_categories p
    on p.tenant_id = t.tenant_id and p.parent_id is null and p.slug = c.parent_slug
  join val_dev.catalog_categories cat
    on cat.tenant_id = t.tenant_id
   and cat.slug = coalesce(c.sub_slug, c.product_slug)
   and (
     (c.sub_slug is null and cat.parent_id = p.id)
     or
     (c.sub_slug is not null and exists (
       select 1 from val_dev.catalog_categories mid
       where mid.tenant_id = t.tenant_id and mid.parent_id = p.id and mid.slug = c.product_slug and cat.parent_id = mid.id
     ))
   )
)
insert into val_dev.catalog_products(
  tenant_id, category_id, name, slug, description, brand, status, default_uom, is_active
)
select
  t.tenant_id,
  pt.category_id,
  pt.product_name,
  'prod-' || md5(pt.product_slug),
  'Seeded from product_summary_clean_v4.xlsx',
  null,
  'active',
  null,
  true
from product_targets pt
cross join tenant t
on conflict (tenant_id, slug)
do nothing;

-- ensure attribute definitions
with tenant as (
  select '11111111-1111-1111-1111-111111111111'::uuid as tenant_id
),
defs(name, code, sort_order) as (
  values
    ('Brand', 'brand', 10),
    ('Type', 'type', 20),
    ('Size/Quantity', 'size_quantity', 30)
)
insert into val_dev.catalog_attribute_definitions(
  tenant_id, name, code, scope, data_type, is_filterable, is_required, sort_order
)
select
  t.tenant_id,
  d.name,
  d.code,
  'variant',
  'select',
  true,
  false,
  d.sort_order
from defs d
cross join tenant t
on conflict (tenant_id, code)
do nothing;

