canon as (
  select
    trim(parent_category) as parent_category,
    trim(product) as product,
    nullif(trim(sub_category), '') as sub_category,
    coalesce(nullif(trim(variant_brand), ''), 'Unknown') as variant_brand,
    coalesce(nullif(trim(variant_type), ''), 'Unknown') as variant_type,
    coalesce(nullif(trim(variant_size_quantity), ''), 'Unknown') as variant_size_quantity,
    trim(variant_label) as variant_label,
    nullif(trim(source_row_id), '') as source_row_id,
    lower(regexp_replace(trim(parent_category), '[^a-zA-Z0-9]+', '-', 'g')) as parent_slug,
    lower(regexp_replace(trim(product), '[^a-zA-Z0-9]+', '-', 'g')) as product_slug,
    case when nullif(trim(sub_category), '') is null then null else lower(regexp_replace(trim(sub_category), '[^a-zA-Z0-9]+', '-', 'g')) end as sub_slug
  from seed_rows
),
attr_defs as (
  select id, code
  from val_dev.catalog_attribute_definitions
  where tenant_id = '11111111-1111-1111-1111-111111111111'::uuid
    and code in ('brand', 'type', 'size_quantity')
),
option_values as (
  select distinct 'brand'::text as code, variant_brand as v from canon
  union all
  select distinct 'type'::text as code, variant_type as v from canon
  union all
  select distinct 'size_quantity'::text as code, variant_size_quantity as v from canon
),
insert_opts as (
  insert into val_dev.catalog_attribute_options(
    tenant_id, attribute_id, label, value, sort_order
  )
  select
    t.tenant_id,
    d.id,
    ov.v,
    lower(regexp_replace(ov.v, '[^a-zA-Z0-9]+', '_', 'g')),
    0
  from option_values ov
  cross join tenant t
  join attr_defs d on d.code = ov.code
  where ov.v is not null and ov.v <> ''
  on conflict (tenant_id, attribute_id, value)
  do nothing
  returning id
),
variant_map as (
  select v.id as variant_id, v.sku
  from val_dev.catalog_product_variants v
  where v.tenant_id = '11111111-1111-1111-1111-111111111111'::uuid
),
rows_for_values as (
  select distinct
    vm.variant_id,
    c.variant_brand,
    c.variant_type,
    c.variant_size_quantity
  from canon c
  cross join tenant t
  join val_dev.catalog_categories pc
    on pc.tenant_id = t.tenant_id and pc.parent_id is null and pc.slug = c.parent_slug
  join val_dev.catalog_categories leaf
    on leaf.tenant_id = t.tenant_id
   and leaf.slug = coalesce(c.sub_slug, c.product_slug)
   and (
     (c.sub_slug is null and leaf.parent_id = pc.id)
     or
     (c.sub_slug is not null and exists (
       select 1 from val_dev.catalog_categories mid
       where mid.tenant_id = t.tenant_id and mid.parent_id = pc.id and mid.slug = c.product_slug and leaf.parent_id = mid.id
     ))
   )
  join val_dev.catalog_products p
    on p.tenant_id = t.tenant_id
   and p.category_id = leaf.id
   and p.slug = 'prod-' || md5(lower(regexp_replace(c.parent_category || '-' || c.product || coalesce('-' || c.sub_category, ''), '[^a-zA-Z0-9]+', '-', 'g')))
  join variant_map vm
    on vm.sku = (
      'VAR-' || upper(substr(md5(
        p.id::text || '|' ||
        coalesce(c.variant_brand, 'Unknown') || '|' ||
        coalesce(c.variant_type, 'Unknown') || '|' ||
        coalesce(c.variant_size_quantity, 'Unknown')
      ), 1, 12))
    )
),
kv as (
  select variant_id, 'brand'::text as code, variant_brand as v from rows_for_values
  union all
  select variant_id, 'type'::text as code, variant_type as v from rows_for_values
  union all
  select variant_id, 'size_quantity'::text as code, variant_size_quantity as v from rows_for_values
)
insert into val_dev.catalog_variant_attribute_values(
  tenant_id, variant_id, attribute_id, value_jsonb
)
select
  t.tenant_id,
  kv.variant_id,
  d.id,
  jsonb_build_object('value', kv.v)
from kv
cross join tenant t
join attr_defs d on d.code = kv.code
on conflict (tenant_id, variant_id, attribute_id)
do nothing;

commit;
